var rows = msg.payload;
if (!rows || rows.length === 0) return null;
var latest = rows[0];
var sorted = rows.slice().reverse();

function p(n){ return n<10?'0'+n:n; }
function fmtDate(d) {
  var dt = new Date(d);
  return dt.getFullYear()+'-'+p(dt.getMonth()+1)+'-'+p(dt.getDate())
    +' '+p(dt.getHours())+':'+p(dt.getMinutes())+':'+p(dt.getSeconds());
}

function pts(field){ return sorted.map(function(r){ return {x:new Date(r.timestamp).getTime(),y:r[field]}; }); }

var chartTH = {payload:[{series:['Temp °C','Humidity %'],
  data:[pts('temperature'),pts('humidity')],labels:['Temp °C','Humidity %']}]};
var chartPL = {payload:[{series:['Pressure hPa','Light lux'],
  data:[pts('pressure'),pts('light_level')],labels:['Pressure hPa','Light lux']}]};

var html = '<div style="width:100%;overflow:hidden;">'
  +'<table style="width:100%;border-collapse:collapse;font-size:13px;table-layout:fixed;">'
  +'<colgroup><col style="width:22%"><col style="width:19%"><col style="width:19%"><col style="width:21%"><col style="width:19%"></colgroup>'
  +'<thead><tr style="background:#374151;color:#f9fafb;">'
  +'<th style="padding:7px 6px;text-align:left;">🕐 Timestamp</th>'
  +'<th style="padding:7px 6px;text-align:center;">🌡️ Temp°C</th>'
  +'<th style="padding:7px 6px;text-align:center;">💧 Humid%</th>'
  +'<th style="padding:7px 6px;text-align:center;">🌬️ Press hPa</th>'
  +'<th style="padding:7px 6px;text-align:center;">☀️ Light lux</th>'
  +'</tr></thead><tbody>';

rows.forEach(function(r,i){
  var bg=i%2===0?'#1f2937':'#111827';
  var tc=r.temperature>35?'#f87171':r.temperature>28?'#fb923c':'#4ade80';
  var hc=r.humidity>80?'#60a5fa':r.humidity>60?'#38bdf8':'#7dd3fc';
  var lc=r.light_level>700?'#fb923c':r.light_level>300?'#facc15':'#94a3b8';
  html+='<tr style="background:'+bg+';">'
    +'<td style="padding:5px 6px;color:#9ca3af;font-size:11px;">'+fmtDate(r.timestamp)+'</td>'
    +'<td style="padding:5px 6px;text-align:center;font-weight:bold;color:'+tc+';">'+r.temperature.toFixed(1)+'</td>'
    +'<td style="padding:5px 6px;text-align:center;font-weight:bold;color:'+hc+';">'+r.humidity.toFixed(1)+'</td>'
    +'<td style="padding:5px 6px;text-align:center;color:#6ee7b7;">'+r.pressure.toFixed(1)+'</td>'
    +'<td style="padding:5px 6px;text-align:center;color:'+lc+';">'+Math.round(r.light_level)+'</td>'
    +'</tr>';
});
html+='</tbody></table></div>';

return [
  [{payload: latest.temperature}],
  [{payload: latest.humidity}],
  [{payload: latest.pressure}],
  [{payload: latest.light_level}],
  [chartTH],
  [chartPL],
  [{payload: html}]
];
